// Package apivalidation holds tests that exercise the GENERATED Goa request-body
// validators from OUTSIDE the generated tree (importing the exported validators),
// so no source lives under gen/ (which is DO-NOT-EDIT, regenerated by `make apigen`).
//
// This guards the Meta connection-config validation contract added in PR #38:
// account_id must match act_<digits>, page_id must be numeric — both Required. A
// regression that relaxed a pattern (letting an unusable id be stored on an active
// connection that can never dispatch) fails here.
package apivalidation

import (
	"strings"
	"testing"

	connsrv "github.com/linuxfoundation/lfx-v2-campaign-service/gen/http/lfx_v2_campaign_service_connections/server"
)

func strp(s string) *string { return &s }

func TestValidateMetaAdsConnectionConfig_PatternsAndRequired(t *testing.T) {
	cases := []struct {
		name      string
		body      *connsrv.MetaAdsConnectionConfigRequestBody
		wantErr   bool
		errSubstr string
	}{
		{
			name: "valid numeric ids",
			body: &connsrv.MetaAdsConnectionConfigRequestBody{AccountID: strp("act_193556282970417"), PageID: strp("123456789012345")},
		},
		{name: "missing account_id", body: &connsrv.MetaAdsConnectionConfigRequestBody{PageID: strp("123")}, wantErr: true, errSubstr: "account_id"},
		{name: "missing page_id", body: &connsrv.MetaAdsConnectionConfigRequestBody{AccountID: strp("act_1")}, wantErr: true, errSubstr: "page_id"},
		{name: "empty page_id", body: &connsrv.MetaAdsConnectionConfigRequestBody{AccountID: strp("act_1"), PageID: strp("")}, wantErr: true, errSubstr: "page_id"},
		{name: "non-numeric page_id", body: &connsrv.MetaAdsConnectionConfigRequestBody{AccountID: strp("act_1"), PageID: strp("page-abc")}, wantErr: true, errSubstr: "page_id"},
		{name: "account_id without act_ prefix", body: &connsrv.MetaAdsConnectionConfigRequestBody{AccountID: strp("193556282970417"), PageID: strp("123")}, wantErr: true, errSubstr: "account_id"},
		{name: "account_id non-numeric", body: &connsrv.MetaAdsConnectionConfigRequestBody{AccountID: strp("act_foo"), PageID: strp("123")}, wantErr: true, errSubstr: "account_id"},
		{name: "empty account_id", body: &connsrv.MetaAdsConnectionConfigRequestBody{AccountID: strp(""), PageID: strp("123")}, wantErr: true, errSubstr: "account_id"},
		// MaxLength(64) boundary: a pattern-valid but over-long id must still 4xx, so the
		// length bound can't silently disappear on regeneration (65 = one over the cap).
		// Exactly one over the MaxLength(64) boundary: "act_" is 4 chars, so 61 digits
		// makes the ID 65 chars — this fails if regeneration relaxed the limit to 65+.
		{name: "overlong account_id", body: &connsrv.MetaAdsConnectionConfigRequestBody{AccountID: strp("act_" + strings.Repeat("9", 61)), PageID: strp("123")}, wantErr: true, errSubstr: "account_id"},
		{name: "overlong page_id", body: &connsrv.MetaAdsConnectionConfigRequestBody{AccountID: strp("act_1"), PageID: strp(strings.Repeat("9", 65))}, wantErr: true, errSubstr: "page_id"},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			err := connsrv.ValidateMetaAdsConnectionConfigRequestBody(tc.body)
			assertValidation(t, err, tc.wantErr, tc.errSubstr)
		})
	}
}

func TestValidateMetaAds_CreateAndUpdate_WrapConfigValidation(t *testing.T) {
	badConfig := &connsrv.MetaAdsConnectionConfigRequestBody{AccountID: strp("act_1"), PageID: strp("not-numeric")}

	createBody := &connsrv.CreateMetaAdsRequestBody{
		Config:      badConfig,
		Credentials: &connsrv.MetaAdsCredentialsRequestBody{AccessToken: strp("tok"), AppSecret: strp("sec")},
	}
	if err := connsrv.ValidateCreateMetaAdsRequestBody(createBody); err == nil || !strings.Contains(err.Error(), "page_id") {
		t.Errorf("create validation must reject a non-numeric page_id, got: %v", err)
	}
	updateBody := &connsrv.UpdateMetaAdsRequestBody{Config: badConfig}
	if err := connsrv.ValidateUpdateMetaAdsRequestBody(updateBody); err == nil || !strings.Contains(err.Error(), "page_id") {
		t.Errorf("update validation must reject a non-numeric page_id, got: %v", err)
	}
}

func assertValidation(t *testing.T, err error, wantErr bool, errSubstr string) {
	t.Helper()
	if wantErr {
		if err == nil {
			t.Fatalf("expected a validation error, got nil")
		}
		if errSubstr != "" && !strings.Contains(err.Error(), errSubstr) {
			t.Errorf("error should mention %q, got: %v", errSubstr, err)
		}
		return
	}
	if err != nil {
		t.Fatalf("expected no validation error, got: %v", err)
	}
}

// TestValidateLinkedinAdsConnectionConfig guards the LinkedIn connection contract added
// in the linkedin PR: account_id and org_id must be numeric (^[0-9]+$) and bounded, so a
// value the client can't interpolate into a request path/URN is a 4xx at connection
// creation rather than an async dispatch failure.
func TestValidateLinkedinAdsConnectionConfig(t *testing.T) {
	cases := []struct {
		name      string
		body      *connsrv.LinkedinAdsConnectionConfigRequestBody
		wantErr   bool
		errSubstr string
	}{
		{name: "valid numeric ids", body: &connsrv.LinkedinAdsConnectionConfigRequestBody{AccountID: strp("538170226"), OrgID: strp("208777")}},
		{name: "missing account_id", body: &connsrv.LinkedinAdsConnectionConfigRequestBody{OrgID: strp("208777")}, wantErr: true, errSubstr: "account_id"},
		{name: "missing org_id", body: &connsrv.LinkedinAdsConnectionConfigRequestBody{AccountID: strp("538170226")}, wantErr: true, errSubstr: "org_id"},
		{name: "non-numeric account_id", body: &connsrv.LinkedinAdsConnectionConfigRequestBody{AccountID: strp("urn:li:sponsoredAccount:538170226"), OrgID: strp("208777")}, wantErr: true, errSubstr: "account_id"},
		{name: "non-numeric org_id (full URN)", body: &connsrv.LinkedinAdsConnectionConfigRequestBody{AccountID: strp("538170226"), OrgID: strp("urn:li:organization:208777")}, wantErr: true, errSubstr: "org_id"},
		{name: "empty account_id", body: &connsrv.LinkedinAdsConnectionConfigRequestBody{AccountID: strp(""), OrgID: strp("208777")}, wantErr: true, errSubstr: "account_id"},
		{name: "overlong org_id", body: &connsrv.LinkedinAdsConnectionConfigRequestBody{AccountID: strp("538170226"), OrgID: strp(strings.Repeat("9", 65))}, wantErr: true, errSubstr: "org_id"},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			assertValidation(t, connsrv.ValidateLinkedinAdsConnectionConfigRequestBody(tc.body), tc.wantErr, tc.errSubstr)
		})
	}
}

// TestValidateTwitterAdsConnectionConfig guards the X/Twitter connection contract
// (LFXV2-2642): account_id AND funding_instrument_id must both match ^[A-Za-z0-9]+$,
// both Required, both MaxLength(64). Both are interpolated into the account-scoped
// request path, so a malformed value stored on an active connection could redirect a
// paid POST — validating here rejects it as a 4xx at creation instead of an async
// dispatch failure.
func TestValidateTwitterAdsConnectionConfig_PatternsAndRequired(t *testing.T) {
	cases := []struct {
		name      string
		body      *connsrv.TwitterAdsConnectionConfigRequestBody
		wantErr   bool
		errSubstr string
	}{
		{name: "valid alphanumeric ids", body: &connsrv.TwitterAdsConnectionConfigRequestBody{AccountID: strp("8r7gb"), FundingInstrumentID: strp("lygyi")}},
		{name: "missing account_id", body: &connsrv.TwitterAdsConnectionConfigRequestBody{FundingInstrumentID: strp("lygyi")}, wantErr: true, errSubstr: "account_id"},
		{name: "missing funding_instrument_id", body: &connsrv.TwitterAdsConnectionConfigRequestBody{AccountID: strp("8r7gb")}, wantErr: true, errSubstr: "funding_instrument_id"},
		{name: "empty account_id", body: &connsrv.TwitterAdsConnectionConfigRequestBody{AccountID: strp(""), FundingInstrumentID: strp("lygyi")}, wantErr: true, errSubstr: "account_id"},
		{name: "empty funding_instrument_id", body: &connsrv.TwitterAdsConnectionConfigRequestBody{AccountID: strp("8r7gb"), FundingInstrumentID: strp("")}, wantErr: true, errSubstr: "funding_instrument_id"},
		{name: "account_id with slash (path-injection)", body: &connsrv.TwitterAdsConnectionConfigRequestBody{AccountID: strp("8r7gb/../x"), FundingInstrumentID: strp("lygyi")}, wantErr: true, errSubstr: "account_id"},
		{name: "funding_instrument_id with slash", body: &connsrv.TwitterAdsConnectionConfigRequestBody{AccountID: strp("8r7gb"), FundingInstrumentID: strp("ly/gyi")}, wantErr: true, errSubstr: "funding_instrument_id"},
		{name: "overlong account_id", body: &connsrv.TwitterAdsConnectionConfigRequestBody{AccountID: strp(strings.Repeat("a", 65)), FundingInstrumentID: strp("lygyi")}, wantErr: true, errSubstr: "account_id"},
		{name: "overlong funding_instrument_id", body: &connsrv.TwitterAdsConnectionConfigRequestBody{AccountID: strp("8r7gb"), FundingInstrumentID: strp(strings.Repeat("a", 65))}, wantErr: true, errSubstr: "funding_instrument_id"},
	}
	for _, tc := range cases {
		t.Run(tc.name, func(t *testing.T) {
			err := connsrv.ValidateTwitterAdsConnectionConfigRequestBody(tc.body)
			assertValidation(t, err, tc.wantErr, tc.errSubstr)
		})
	}
}
